#!/usr/bin/env python3
"""Step 1: Fix H1 headings in all daily/weekly/monthly files across vault."""

import re, sys
from pathlib import Path
from datetime import datetime

VAULT = Path("/Users/brunner/repos/nikbrunner/notes")
DRY = "--dry" in sys.argv

def day_num_to_name(n):
    return ["Mon", "Tue", "Wed", "Thu", "Fri", "Sat", "Sun"][n]

def month_num_to_name(n):
    return ["January", "February", "March", "April", "May", "June",
            "July", "August", "September", "October", "November", "December"][n - 1]

# Daily H1: # YYYY.MM.DD - Ddd
DAILY_H1_RE = re.compile(r'^# (\d{4})\.(\d{2})\.(\d{2})\s*-\s*(.+?)(?:\s+\d+)?$', re.MULTILINE)
# Monthly H1: # YYYY.MM - Mmmm
MONTHLY_H1_RE = re.compile(r'^# (\d{4})\.(\d{2})\s*-\s*(.+?)$', re.MULTILINE)
# Weekly H1: # YYYY.MM - Mmmm - WXX
WEEKLY_H1_RE = re.compile(r'^# (\d{4})\.(\d{2})\s*-\s*(.+?)\s*-\s*W(\d+)$', re.MULTILINE)

def parse_filename_stem(stem):
    """Parse date from file stem. Returns (type, year, month, day_or_week, extra) or None."""
    # DD.MM.YYYY - Ddd (active logs)
    m = re.match(r'^(\d{2})\.(\d{2})\.(\d{4})\s*-\s*(\w+)$', stem)
    if m:
        d, mo, y, _ = m.groups()
        return ('daily', int(y), int(mo), int(d), None)

    # YYYY.MM.DD - Ddd or Ddddd (archive 2025, target)
    m = re.match(r'^(\d{4})\.(\d{2})\.(\d{2})\s*-\s*(\w+)$', stem)
    if m:
        y, mo, d, _ = m.groups()
        return ('daily', int(y), int(mo), int(d), None)

    # YY.MM.DD - Ddd or Ddddd (archive 2020-2024, 2022-2023)
    m = re.match(r'^(\d{2})\.(\d{2})\.(\d{2})\s*-\s*(\w+)$', stem)
    if m:
        yy, mo, d, _ = m.groups()
        y_int = int(yy)
        y = 2000 + y_int if y_int <= 25 else 1900 + y_int
        return ('daily', y, int(mo), int(d), None)

    # MM.YYYY - WXX (active logs weekly)
    m = re.match(r'^(\d{2})\.(\d{4})\s*-\s*W(\d+)$', stem)
    if m:
        mo, y, w = m.groups()
        return ('weekly', int(y), int(mo), None, int(w))

    # YYYY.MM - WXX (target weekly)
    m = re.match(r'^(\d{4})\.(\d{2})\s*-\s*W(\d+)$', stem)
    if m:
        y, mo, w = m.groups()
        return ('weekly', int(y), int(mo), None, int(w))

    # YY.MM - WXX (archive weekly)
    m = re.match(r'^(\d{2})\.(\d{2})\s*-\s*W(\d+)$', stem)
    if m:
        yy, mo, w = m.groups()
        y_int = int(yy)
        y = 2000 + y_int if y_int <= 25 else 1900 + y_int
        return ('weekly', y, int(mo), None, int(w))

    # MM.YYYY (active logs monthly)
    m = re.match(r'^(\d{2})\.(\d{4})$', stem)
    if m:
        mo, y = m.groups()
        return ('monthly', int(y), int(mo), None, None)

    # YYYY.MM - Mmmm (archive/active monthly)
    m = re.match(r'^(\d{4})\.(\d{2})\s*-\s*(.+)$', stem)
    if m:
        y, mo, _ = m.groups()
        return ('monthly', int(y), int(mo), None, None)

    # YYYY.MM (target monthly)
    m = re.match(r'^(\d{4})\.(\d{2})$', stem)
    if m:
        y, mo = m.groups()
        return ('monthly', int(y), int(mo), None, None)

    # YY.MM - Mmmm (archive monthly like "24.01 - January")
    m = re.match(r'^(\d{2})\.(\d{2})\s*-\s*\w+$', stem)
    if m:
        yy, mo = m.groups()
        y_int = int(yy)
        y = 2000 + y_int if y_int <= 25 else 1900 + y_int
        return ('monthly', y, int(mo), None, None)

    return None


def fix_h1(filepath):
    try:
        content = filepath.read_text(encoding='utf-8')
    except Exception:
        return None

    stem = filepath.stem
    parsed = parse_filename_stem(stem)
    if not parsed:
        return None

    ftype, y, m, d_or_w, extra = parsed

    if ftype == 'daily':
        expected = f"# {y:04d}.{m:02d}.{d_or_w:02d} - {day_num_to_name(datetime(y, m, d_or_w).weekday())}"
    elif ftype == 'weekly':
        month_name = month_num_to_name(m)
        expected = f"# {y:04d}.{m:02d} - {month_name} - W{extra:02d}"
    elif ftype == 'monthly':
        month_name = month_num_to_name(m)
        expected = f"# {y:04d}.{m:02d} - {month_name}"
    else:
        return None

    lines = content.split('\n')
    new_lines = []
    found = False

    for line in lines:
        if ftype == 'daily':
            mh = DAILY_H1_RE.match(line)
        elif ftype == 'weekly':
            mh = WEEKLY_H1_RE.match(line)
        else:
            mh = MONTHLY_H1_RE.match(line)

        if mh and not found:
            found = True
            if line.rstrip() != expected:
                new_lines.append(expected)
            else:
                new_lines.append(line)
        else:
            new_lines.append(line)

    if not found:
        # Insert after frontmatter closing --- or at top
        result = []
        in_fm = False
        done = False
        for line in lines:
            result.append(line)
            if not done:
                if line.strip() == '---':
                    if in_fm:
                        done = True
                        result.append(expected)
                    in_fm = not in_fm
        if not done:
            result.insert(0, expected)
        new_lines = result

    new_content = '\n'.join(new_lines)
    if new_content != content:
        if not DRY:
            filepath.write_text(new_content, encoding='utf-8')
        return expected
    return None


def main():
    fixed = 0
    areas = ["02 - Areas/Log", "04 - Archive/Historical Logs"]
    for area in areas:
        area_path = VAULT / area
        if not area_path.exists():
            continue
        for f in area_path.rglob("*.md"):
            result = fix_h1(f)
            if result:
                fixed += 1
                if DRY:
                    print(f"  [DRY] {f.relative_to(VAULT)} → {result}")

    print(f"\nH1 fixes: {fixed}" + (" (dry run)" if DRY else ""))

if __name__ == "__main__":
    main()

