#!/usr/bin/env python3
"""Cleanup: remove old-format H1s that were duplicated during migration."""

import re, sys
from pathlib import Path

VAULT = Path("/Users/brunner/repos/nikbrunner/notes")
DRY = "--dry" in sys.argv

# Old format H1: # YY.MM.DD - Ddd or # YY.MM.DD - Ddddd
OLD_H1_RE = re.compile(r'^# (\d{2})\.(\d{2})\.(\d{2})\s*-\s*(\w+)', re.MULTILINE)
# New format H1: # YYYY.MM.DD - Ddd
NEW_H1_RE = re.compile(r'^# (\d{4})\.(\d{2})\.(\d{2})\s*-\s*\w+', re.MULTILINE)

areas = ["02 - Areas/Log", "04 - Archive/Historical Logs"]

def clean_file(filepath):
    try:
        content = filepath.read_text(encoding='utf-8')
    except Exception:
        return False

    old_matches = list(OLD_H1_RE.finditer(content))
    new_matches = list(NEW_H1_RE.finditer(content))

    if not old_matches or not new_matches:
        return False

    # Remove lines that match old H1 pattern
    lines = content.split('\n')
    new_lines = []
    for line in lines:
        if OLD_H1_RE.match(line):
            continue  # skip old H1
        new_lines.append(line)

    new_content = '\n'.join(new_lines)
    if new_content != content:
        if not DRY:
            filepath.write_text(new_content, encoding='utf-8')
        return True
    return False


def main():
    cleaned = 0
    for area in areas:
        area_path = VAULT / area
        if not area_path.exists():
            continue
        for f in area_path.rglob("*.md"):
            if clean_file(f):
                cleaned += 1
                if DRY:
                    print(f"  [DRY] {f.relative_to(VAULT)}")

    print(f"\nCleaned {cleaned} files" + (" (dry run)" if DRY else ""))

if __name__ == "__main__":
    main()
